import React, { useState } from 'react';
import axios from 'axios';

function AddTask() {
  const [formData, setFormData] = useState({
    name: '',
    startDate: '',
    endDate: '',
    importance: '',
    urgency: '',
    description: '',
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await axios.post('http://localhost:5000/add-task', formData);
      alert('일정이 성공적으로 추가되었습니다!');
    } catch (err) {
      alert('일정 추가 중 오류 발생: ' + err.message);
    }
  };

  return (
    <div>
      <h1>일정 추가</h1>
      <form onSubmit={handleSubmit}>
        <div>
          <label>이름:</label>
          <input type="text" name="name" value={formData.name} onChange={handleChange} required />
        </div>
        <div>
          <label>시작 날짜:</label>
          <input type="date" name="startDate" value={formData.startDate} onChange={handleChange} required />
        </div>
        <div>
          <label>종료 날짜:</label>
          <input type="date" name="endDate" value={formData.endDate} onChange={handleChange} required />
        </div>
        <div>
          <label>중요도:</label>
          <input type="number" name="importance" value={formData.importance} onChange={handleChange} required />
        </div>
        <div>
          <label>긴급도:</label>
          <input type="number" name="urgency" value={formData.urgency} onChange={handleChange} required />
        </div>
        <div>
          <label>설명:</label>
          <textarea name="description" value={formData.description} onChange={handleChange}></textarea>
        </div>
        <button type="submit">추가</button>
      </form>
    </div>
  );
}

export default AddTask;
